void allocHostMem(int num, int dim) {
  size_t need = (size_t)num * (size_t)dim;
  if (need > coord_h_cap) {
    free(coord_h);
    coord_h = (float*)malloc(need * sizeof(float));
    coord_h_cap = need;
  }
}

void allocDevMem(int num, int dim) {
  size_t n = (size_t)num;
  size_t coord_need = (size_t)num * (size_t)dim;

  if (n > center_table_cap) {
    free(center_table_d);
    center_table_d = (int*)malloc(n * sizeof(int));
    center_table_cap = n;
  }
  if (n > switch_membership_cap) {
    free(switch_membership_d);
    switch_membership_d = (bool*)malloc(n * sizeof(bool));
    switch_membership_cap = n;
  }
  if (n > p_cap) {
    free(p_dev);
    p_dev = (Point*)malloc(n * sizeof(Point));
    p_cap = n;
  }
  if (coord_need > coord_d_cap) {
    free(coord_d);
    coord_d = (float*)malloc(coord_need * sizeof(float));
    coord_d_cap = coord_need;
  }
}

void freeDevMem() {
